export default function PolicySectionWrapper() {
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const section = searchParams.get("section");

  const [active, setActive] = useState<SectionKey>(() => {
    return (section as SectionKey) || "terms";
  });

  const [fade, setFade] = useState(true);
  const sectionRef = useRef<HTMLDivElement>(null);

  const path = location.pathname;
  const isEHR = path.startsWith("/industries/ehr-and-pms");
  const isBanking = path.startsWith("/industries/banking-and-finance");

  const COLORS = {
    ehr: {
      BgColor: "#FFFFFF",
      TextColor: "#166D48", // Green for headings
      ParagraphColor: "#000000", // Black for paragraphs
      AccentColor: "#166D48", // Green for left line
      BtnTextColor: "#FFFFFF", // Green for button text
      BtnBgInactive: "#166D4820",
    },
    banking: {
      BgColor: "#FFFFFF",
      TextColor: "#00AA72", // Blue for headings
      ParagraphColor: "#000000", // Black for paragraphs
      AccentColor: "#00AA72", // Blue for left line
      BtnTextColor: "#FFFFFF", // Blue for button text
      BtnBgInactive: "#00AA7220",
    },
    hightech: {
      BgColor: "#000000",
      TextColor: "#F99526", // Orange for headings
      ParagraphColor: "#CCCCCC", 
      AccentColor: "#F99526", // Orange for left line
      BtnTextColor: "#FFFFFF", // White for button text
      BtnBgInactive: "#F9952620",
    },
  };

  const theme = isEHR
    ? COLORS.ehr
    : isBanking
    ? COLORS.banking
    : COLORS.hightech;
  
  const { BgColor, TextColor, ParagraphColor, AccentColor, BtnTextColor } = theme;

  const getText = (key: SectionKey) => {
    switch (key) {
      case "terms":
        return TERMS_TEXT;
      case "privacy":
        return PRIVACY_TEXT;
      case "cookies":
        return COOKIES_TEXT;
    }
  };
 
 
 const switchSection = (key: SectionKey) => {
  if (key === active) return;

  setFade(false); // fade out

    setFade(false); // fade out

    setTimeout(() => {
      setActive(key); // change text
      setFade(true);  // fade back in
      
      // Scroll to top of section after animation
      sectionRef.current?.scrollIntoView({ 
        behavior: 'smooth', 
        block: 'start' 
      });
    }, 200);
  };

  const allButtons = [
    { key: "terms" as SectionKey, label: "Terms & Conditions" },
    { key: "privacy" as SectionKey, label: "Privacy Policy" },
    { key: "cookies" as SectionKey, label: "Cookie Policy" },
  ];

  return (
    <section
      className="w-full py-12 px-10  mt-20 transition-colors duration-500"
      style={{
        backgroundColor: BgColor,
        color: TextColor,
      }}
    >
      <div
        ref={sectionRef}
        className="max-w-8xl mx-10 flex flex-col lg:flex-row justify-between gap-12 pt-22"
      >
        {/* LEFT CONTENT */}
        <div className="w-full lg:w-[70%]">
          <div className="flex items-center justify-between pb-6">
            <H1
              className="text-4xl sm:text-5xl font-extrabold"
              style={{ color: AccentColor }}
            >
              {active === "terms"
                ? "Terms and Conditions"
                : active === "privacy"
                ? "Privacy Policy"
                : "Cookie Policy"}
            </H1>
          </div>
 
          {/* <H4
            className="text-sm sm:text-base font-semibold mb-8 transition-colors duration-500"
            style={{ color: AccentColor }}
          >
            {EFFECTIVE_DATES[active]}
          </H4> */}
 
          <div
            className={`mt-6 space-y-8 whitespace-pre-wrap transition-opacity duration-300 ${
              fade ? "opacity-100" : "opacity-0"
            } text-base leading-relaxed`}
          >
            {getText(active)
              .split("\n\n")
              .map((p, i) => (
                <p
                  key={i}
                  className="text-sm md:text-base leading-relaxed mb-4"
                  style={{ color: ParagraphColor }}
                >
                  {p}
                </p>
              ))}
          </div>
        </div>

        {/* RIGHT NAV */}
        <div className="relative w-full lg:w-[22%] flex-shrink-0">
          <div className="lg:sticky lg:top-24">
            <div className="text-right mb-6 pr-4">
              <p 
                className="text-xl lg:text-2xl font-semibold"
                style={{ color: ParagraphColor }}
              >
                {EFFECTIVE_DATES[active]}
              </p>
            </div>

            {/* Glow */}
            <div
              className={`
                absolute
                top-[-200px] sm:top-[-250px] lg:top-[-120px]
                left-[0px] sm:left-[10px] lg:left-[50px]
                w-[250px] sm:w-[300px] md:w-[330px] lg:w-[300px]
                h-[250px] sm:h-[300px] md:h-[330px] lg:h-[500px]
                opacity-20
                blur-[100px]
                rounded-full
                z-0
                pointer-events-none
              `}
              style={{ backgroundColor: AccentColor }}
            />

            <div className="flex relative z-10">
              <div
                className="w-[3px]"
                style={{ backgroundColor: AccentColor }}
              />

              <div className="flex flex-col w-full">
                {allButtons.map((btn) => {
                  const isActive = btn.key === active;
                  return (
                    <button
                      key={btn.key}
                      onClick={() => switchSection(btn.key)}
                      className={`
                        relative
                        text-left font-medium
                        px-4 py-3
                        text-sm md:text-base
                        transition-colors duration-200
                        hover:bg-[#222222]/90
                      `}
                      style={{
                        backgroundColor: isActive ? "#222222" : "#333333",
                        color: BtnTextColor,
                      }}
                    >
                      {btn.label}
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}